try {
  const data = $input.first().json;
  const body = data.body || data;
  const events = body.events || [];

  if (!events.length) {
    return [{ json: { command: "none", args: "", replyToken: "", rawText: "" } }];
  }

  const event = events[0];
  const replyToken = event.replyToken || "";
  const msgText = (event.message && event.message.text) || "";

  let command = "default";
  let args = msgText;

  if (msgText.startsWith("/")) {
    const spaceIdx = msgText.indexOf(" ");
    if (spaceIdx > 0) {
      command = msgText.substring(0, spaceIdx).toLowerCase();
      args = msgText.substring(spaceIdx + 1).trim();
    } else {
      command = msgText.toLowerCase();
      args = "";
    }
  }

  return [{ json: { command, args, replyToken, rawText: msgText } }];
} catch (e) {
  return [{ json: { command: "error", args: e.message, replyToken: "", rawText: "" } }];
}

const xml = $input.first().json.data || $input.first().json;
const text = typeof xml === 'string' ? xml : JSON.stringify(xml);
const titles = [];
const matches = text.match(/<title>([^<]+)<\/title>/g) || [];
for (let i = 1; i <= Math.min(5, matches.length - 1); i++) {
  const t = matches[i].replace(/<\/?title>/g, '');
  titles.push((i) + '. ' + t);
}
const msg = 'AI 最新新聞 Top 5\n━━━━━━━━━━\n\n' + titles.join('\n\n');
return [{ json: { newsText: msg, replyToken: $('Parse Command').first().json.replyToken } }];

const data = $input.first().json.data || [];
const total = data.length;
const success = data.filter(e => e.status === 'success').length;
const errors = data.filter(e => e.status === 'error').length;
const rate = total > 0 ? Math.round(success / total * 100) : 0;
const failed = data.filter(e => e.status === 'error').slice(0, 3).map(e => e.workflowId).join(', ');
const msg = 'n8n Cloud 狀態（最近 50 筆）\n━━━━━━━━━━\n\n成功：' + success + '\n失敗：' + errors + '\n成功率：' + rate + '%\n\n' + (errors > 0 ? '最近失敗：' + failed : '全部成功！');
return [{ json: { statsText: msg, replyToken: $('Parse Command').first().json.replyToken } }];

const keyword = $("Parse Command").first().json.args;
let text = '';
try {
  const raw = $input.first().json;
  let parsed = raw;
  if (typeof raw.data === 'string') {
    parsed = JSON.parse(raw.data);
  }
  const prods = parsed.prods || [];
  const items = [];
  const nl = String.fromCharCode(10);
  for (let i = 0; i < Math.min(5, prods.length); i++) {
    const name = (prods[i].name || '').substring(0, 35);
    const price = prods[i].price || '?';
    items.push((i+1) + '. ' + name + nl + '   $' + price);
  }
  text = 'PChome 搜尋：' + keyword + nl + '━━━━━━━━━━' + nl + nl + (items.length > 0 ? items.join(nl + nl) : '無結果');
} catch(e) {
  text = 'PChome 搜尋 ' + keyword + '：' + e.message;
}
return [{ json: { searchText: text, replyToken: $("Parse Command").first().json.replyToken } }];

const token = $("Parse Command").first().json.replyToken;
const nl = String.fromCharCode(10);
const lines = [
  "LINE Bot 命令列表",
  "━━━━━━━━━━",
  "",
  "/help  顯示此說明",
  "/天氣 /weather  台北天氣",
  "/新聞 /news  AI 新聞 Top 5",
  "/日報 /daily  觸發日報",
  "/圖表 /sketch  手繪圖表",
  "/訂閱 /schedule  查看排程",
  "/n8n  n8n 執行狀態",
  "/找 /find 關鍵字  PChome 搜尋",
  "/研究 /research 公司名  公司研究",
  "",
  "範例：/find 充電器",
  "範例：/research Anthropic"
];
const text = lines.join(nl);
const body = JSON.stringify({ replyToken: token, messages: [{ type: "text", text }] });
return [{ json: { body } }];

